import pytest

def compose(*fns):
    def composed(x):
        for fn in reversed(fns):
            x = fn(x)
        return x
    return composed

def test_compose_happy_path():
    def add_one(x):
        return x + 1

    def multiply_by_two(x):
        return x * 2

    composed_function = compose(multiply_by_two, add_one)
    assert composed_function(3) == 8  # (3 + 1) * 2 = 8

def test_compose_multiple_functions():
    def add_one(x):
        return x + 1

    def multiply_by_two(x):
        return x * 2

    def subtract_three(x):
        return x - 3

    composed_function = compose(subtract_three, multiply_by_two, add_one)
    assert composed_function(3) == 5  # ((3 + 1) * 2) - 3 = 5

def test_compose_single_function():
    def add_one(x):
        return x + 1

    composed_function = compose(add_one)
    assert composed_function(3) == 4

def test_compose_no_functions():
    composed_function = compose()
    assert composed_function(3) == 3  # Should return the input unchanged

def test_compose_with_lambda():
    composed_function = compose(lambda x: x * 2, lambda x: x + 1)
    assert composed_function(3) == 8

def test_compose_with_different_data_types():
    def stringify(x):
        return str(x)

    def add_prefix(x):
        return "Result: " + x

    composed_function = compose(add_prefix, stringify)
    assert composed_function(10) == "Result: 10"

def test_compose_with_function_returning_none():
    def return_none(x):
        return None

    def add_one(x):
        return x + 1

    composed_function = compose(add_one, return_none)
    with pytest.raises(TypeError):
        composed_function(3) # add_one(None) will raise TypeError

def test_compose_with_function_expecting_specific_type():
    def string_length(s):
        return len(s)

    def add_one(x):
        return x + 1

    composed_function = compose(string_length, add_one)
    with pytest.raises(TypeError):
        composed_function("hello") # string_length(6) will raise TypeError

def test_compose_with_function_raising_exception():
    def raise_exception(x):
        raise ValueError("Something went wrong")

    def add_one(x):
        return x + 1

    composed_function = compose(add_one, raise_exception)
    with pytest.raises(ValueError) as excinfo:
        composed_function(3)
    assert str(excinfo.value) == "Something went wrong"
